using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Preserve EF Core 8 discriminator property name (EF Core 9 defaults to "$type")
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Preserve EF Core 8 id format "Blog|1" (EF Core 9 defaults to key-only)
        modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

        // HasIndex removed — Cosmos DB does not support EF-managed indexes;
        // manage indexing policy via Azure Portal or infrastructure-as-code.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

